pub type Frame = signal_frame::StreamingFrame<Input, Output, IntentEvent>;
#[rustfmt::skip]
pub type FrameBody = signal_frame::StreamingFrameBody<Input, Output, IntentEvent>;
#[rustfmt::skip]
